export const ATLAS_VERSION = '5.6.0';

export const ATLAS_TACTICS = [
  { id: 'AML.TA0002', name: 'Reconnaissance', description: 'The adversary is trying to gather information about the AI system they can use to plan future operations. Reconnaissance consists of techniques that involve adversaries actively or passively gathering information that can be used to support targeting. Such information may include details of the victim organizations\' AI capabilities and research efforts. This information can be leveraged by the adv' },
  { id: 'AML.TA0003', name: 'Resource Development', description: 'The adversary is trying to establish resources they can use to support operations. Resource Development consists of techniques that involve adversaries creating, purchasing, or compromising/stealing resources that can be used to support targeting. Such resources include AI artifacts, infrastructure, accounts, or capabilities. These resources can be leveraged by the adversary to aid in other phases' },
  { id: 'AML.TA0004', name: 'Initial Access', description: 'The adversary is trying to gain access to the AI system. The target system could be a network, mobile device, or an edge device such as a sensor platform. The AI capabilities used by the system could be local with onboard or cloud-enabled AI capabilities. Initial Access consists of techniques that use various entry vectors to gain their initial foothold within the system.' },
  { id: 'AML.TA0000', name: 'AI Model Access', description: 'The adversary is attempting to gain some level of access to an AI model. AI Model Access enables techniques that use various types of access to the AI model that can be used by the adversary to gain information, develop attacks, and as a means to input data to the model. The level of access can range from the full knowledge of the internals of the model to access to the physical environment where ' },
  { id: 'AML.TA0005', name: 'Execution', description: 'The adversary is trying to run malicious code embedded in AI artifacts or software. Execution consists of techniques that result in adversary-controlled code running on a local or remote system. Techniques that run malicious code are often paired with techniques from all other tactics to achieve broader goals, like exploring a network or stealing data. For example, an adversary might use a remote ' },
  { id: 'AML.TA0006', name: 'Persistence', description: 'The adversary is trying to maintain their foothold via AI artifacts or software. Persistence consists of techniques that adversaries use to keep access to systems across restarts, changed credentials, and other interruptions that could cut off their access. Techniques used for persistence often involve leaving behind modified ML artifacts such as poisoned training data or manipulated AI models.' },
  { id: 'AML.TA0012', name: 'Privilege Escalation', description: 'The adversary is trying to gain higher-level permissions. Privilege Escalation consists of techniques that adversaries use to gain higher-level permissions on a system or network. Adversaries can often enter and explore a network with unprivileged access but require elevated permissions to follow through on their objectives. Common approaches are to take advantage of system weaknesses, misconfigur' },
  { id: 'AML.TA0007', name: 'Defense Evasion', description: 'The adversary is trying to avoid being detected by AI-enabled security software. Defense Evasion consists of techniques that adversaries use to avoid detection throughout their compromise. Techniques used for defense evasion include evading AI-enabled security software such as malware detectors.' },
  { id: 'AML.TA0013', name: 'Credential Access', description: 'The adversary is trying to steal account names and passwords. Credential Access consists of techniques for stealing credentials like account names and passwords. Techniques used to get credentials include keylogging or credential dumping. Using legitimate credentials can give adversaries access to systems, make them harder to detect, and provide the opportunity to create more accounts to help achi' },
  { id: 'AML.TA0008', name: 'Discovery', description: 'The adversary is trying to figure out your AI environment. Discovery consists of techniques an adversary may use to gain knowledge about the system and internal network. These techniques help adversaries observe the environment and orient themselves before deciding how to act. They also allow adversaries to explore what they can control and what\'s around their entry point in order to discover how ' },
  { id: 'AML.TA0015', name: 'Lateral Movement', description: 'The adversary is trying to move through your AI environment. Lateral Movement consists of techniques that adversaries may use to gain access to and control other systems or components in the environment. Adversaries may pivot towards AI Ops infrastructure such as model registries, experiment trackers, vector databases, notebooks, or training pipelines. As the adversary moves through the environmen' },
  { id: 'AML.TA0009', name: 'Collection', description: 'The adversary is trying to gather AI artifacts and other related information relevant to their goal. Collection consists of techniques adversaries may use to gather information and the sources information is collected from that are relevant to following through on the adversary\'s objectives. Frequently, the next goal after collecting data is to steal (exfiltrate) the AI artifacts, or use the colle' },
  { id: 'AML.TA0001', name: 'AI Attack Staging', description: 'The adversary is leveraging their knowledge of and access to the target system to tailor the attack. AI Attack Staging consists of techniques adversaries use to prepare their attack on the target AI model. Techniques can include training proxy models, poisoning the target model, and crafting adversarial data to feed the target model. Some of these techniques can be performed in an offline manner a' },
  { id: 'AML.TA0014', name: 'Command and Control', description: 'The adversary is trying to communicate with compromised AI systems to control them. Command and Control consists of techniques that adversaries may use to communicate with systems under their control within a victim network. Adversaries commonly attempt to mimic normal, expected traffic to avoid detection. There are many ways an adversary can establish command and control with various levels of st' },
  { id: 'AML.TA0010', name: 'Exfiltration', description: 'The adversary is trying to steal AI artifacts or other information about the AI system. Exfiltration consists of techniques that adversaries may use to steal data from your network. Data may be stolen for its valuable intellectual property, or for use in staging future operations. Techniques for getting data out of a target network typically include transferring it over their command and control c' },
  { id: 'AML.TA0011', name: 'Impact', description: 'The adversary is trying to manipulate, interrupt, erode confidence in, or destroy your AI systems and data. Impact consists of techniques that adversaries use to disrupt availability or compromise integrity by manipulating business and operational processes. Techniques used for impact can include destroying or tampering with data. In some cases, business processes can look fine, but may have been ' },
];

// Top-level techniques only (sub-techniques omitted to keep this maintainable;
// pull sub-techniques from the full ATLAS.yaml if you need that granularity).
export const ATLAS_TECHNIQUES = [
  { id: 'AML.T0000', name: 'Search Open Technical Databases', tactics: ['AML.TA0002'], description: 'Adversaries may search for publicly available research and technical documentation to learn how and where AI is used within a victim organization. The adversary can use this information to identify targets for attack, or to tailor an existing attack to make it more effective. Organizations often use open source model architectures trained on additional proprietary data in production. Knowledge of ' },
  { id: 'AML.T0001', name: 'Search Open AI Vulnerability Analysis', tactics: ['AML.TA0002'], description: 'Much like the Search Open Technical Databases, there is often ample research available on the vulnerabilities of common AI models. Once a target has been identified, an adversary will likely try to identify any pre-existing work that has been done for this class of models. This will include not only reading academic papers that may identify the particulars of a successful attack, but also identify' },
  { id: 'AML.T0003', name: 'Search Victim-Owned Websites', tactics: ['AML.TA0002'], description: 'Adversaries may search websites owned by the victim for information that can be used during targeting. Victim-owned websites may contain technical details about their AI-enabled products or services. Victim-owned websites may contain a variety of details, including names of departments/divisions, physical locations, and data about key employees such as names, roles, and contact info. These sites m' },
  { id: 'AML.T0004', name: 'Search Application Repositories', tactics: ['AML.TA0002'], description: 'Adversaries may search open application repositories during targeting. Examples of these include Google Play, the iOS App store, the macOS App Store, and the Microsoft Store. Adversaries may craft search queries seeking applications that contain AI-enabled components. Frequently, the next step is to Acquire Public AI Artifacts.' },
  { id: 'AML.T0006', name: 'Active Scanning', tactics: ['AML.TA0002'], description: 'An adversary may probe or scan the victim system to gather information for targeting. This is distinct from other reconnaissance techniques that do not involve direct interaction with the victim system. Adversaries may scan for open ports on a potential victim\'s network, which can indicate specific services or tools the victim is utilizing. This could include a scan for tools related to AI DevOps ' },
  { id: 'AML.T0002', name: 'Acquire Public AI Artifacts', tactics: ['AML.TA0003'], description: 'Adversaries may search public sources, including cloud storage, public-facing services, and software or data repositories, to identify AI artifacts. These AI artifacts may include the software stack used to train and deploy models, training and testing data, model configurations and parameters. An adversary will be particularly interested in artifacts hosted by or associated with the victim organi' },
  { id: 'AML.T0016', name: 'Obtain Capabilities', tactics: ['AML.TA0003'], description: 'Adversaries may search for and obtain software capabilities for use in their operations. Capabilities may be specific to AI-based attacks Adversarial AI Attack Implementations or generic software tools repurposed for malicious intent (Software Tools). In both instances, an adversary may modify or customize the capability to aid in targeting a particular AI-enabled system.' },
  { id: 'AML.T0017', name: 'Develop Capabilities', tactics: ['AML.TA0003'], description: 'Adversaries may develop their own capabilities to support operations. This process encompasses identifying requirements, building solutions, and deploying capabilities. Capabilities used to support attacks on AI-enabled systems are not necessarily AI-based themselves. Examples include setting up websites with adversarial information or creating Jupyter notebooks with obfuscated exfiltration code.' },
  { id: 'AML.T0008', name: 'Acquire Infrastructure', tactics: ['AML.TA0003'], description: 'Adversaries may buy, lease, or rent infrastructure for use throughout their operation. A wide variety of infrastructure exists for hosting and orchestrating adversary operations. Infrastructure solutions include physical or cloud servers, domains, mobile devices, and third-party web services. Free resources may also be used, but they are typically limited. Infrastructure can also include physical ' },
  { id: 'AML.T0019', name: 'Publish Poisoned Datasets', tactics: ['AML.TA0003'], description: 'Adversaries may Poison Training Data and publish it to a public location. The poisoned dataset may be a novel dataset or a poisoned variant of an existing open source dataset. This data may be introduced to a victim system via AI Supply Chain Compromise.' },
  { id: 'AML.T0010', name: 'AI Supply Chain Compromise', tactics: ['AML.TA0004'], description: 'Adversaries may gain initial access to a system by compromising the unique portions of the AI supply chain. This could include Hardware, Data and its annotations, parts of the AI AI Software stack, or the Model itself. In some instances the attacker will need secondary access to fully carry out an attack using compromised components of the supply chain.' },
  { id: 'AML.T0040', name: 'AI Model Inference API Access', tactics: ['AML.TA0000'], description: 'Adversaries may gain access to a model via legitimate access to the inference API. Inference API access can be a source of information to the adversary (Discover AI Model Ontology, Discover AI Model Family), a means of staging the attack (Verify Attack, Craft Adversarial Data), or for introducing data to the target system for Impact (Evade AI Model, Erode AI Model Integrity). Many systems rely on ' },
  { id: 'AML.T0047', name: 'AI-Enabled Product or Service', tactics: ['AML.TA0000'], description: 'Adversaries may use a product or service that uses artificial intelligence under the hood to gain access to the underlying AI model. This type of indirect model access may reveal details of the AI model or its inferences in logs or metadata.' },
  { id: 'AML.T0041', name: 'Physical Environment Access', tactics: ['AML.TA0000'], description: 'In addition to the attacks that take place purely in the digital domain, adversaries may also exploit the physical environment for their attacks. If the model is interacting with data collected from the real world in some way, the adversary can influence the model through access to wherever the data is being collected. By modifying the data in the collection process, the adversary can perform modi' },
  { id: 'AML.T0044', name: 'Full AI Model Access', tactics: ['AML.TA0000'], description: 'Adversaries may gain full "white-box" access to an AI model. This means the adversary has complete knowledge of the model architecture, its parameters, and class ontology. They may exfiltrate the model to Craft Adversarial Data and Verify Attack in an offline where it is hard to detect their behavior.' },
  { id: 'AML.T0013', name: 'Discover AI Model Ontology', tactics: ['AML.TA0008'], description: 'Adversaries may discover the ontology of an AI model\'s output space, for example, the types of objects a model can detect. The adversary may discovery the ontology by repeated queries to the model, forcing it to enumerate its output space. Or the ontology may be discovered in a configuration file or in documentation about the model. The model ontology helps the adversary understand how the model i' },
  { id: 'AML.T0014', name: 'Discover AI Model Family', tactics: ['AML.TA0008'], description: 'Adversaries may discover the general family of model. General information about the model may be revealed in documentation, or the adversary may use carefully constructed examples and analyze the model\'s responses to categorize it. Knowledge of the model family can help the adversary identify means of attacking the model and help tailor the attack.' },
  { id: 'AML.T0020', name: 'Poison Training Data', tactics: ['AML.TA0003', 'AML.TA0006'], description: 'Adversaries may attempt to poison datasets used by an AI model by modifying the underlying data or its labels. This allows the adversary to embed vulnerabilities in AI models trained on the data that may not be easily detectable. Data poisoning attacks may or may not require modifying the labels. The embedded vulnerability is activated at a later time by data samples with an Insert Backdoor Trigge' },
  { id: 'AML.T0021', name: 'Establish Accounts', tactics: ['AML.TA0003'], description: 'Adversaries may create accounts with various services for use in targeting, to gain access to resources needed in AI Attack Staging, or for victim impersonation.' },
  { id: 'AML.T0005', name: 'Create Proxy AI Model', tactics: ['AML.TA0001'], description: 'Adversaries may obtain models to serve as proxies for the target model in use at the victim organization. Proxy models are used to simulate complete access to the target model in a fully offline manner. Adversaries may train models from representative datasets, attempt to replicate models from victim inference APIs, or use available pre-trained models.' },
  { id: 'AML.T0007', name: 'Discover AI Artifacts', tactics: ['AML.TA0008'], description: 'Adversaries may search private sources to identify AI learning artifacts that exist on the system and gather information about them. These artifacts can include the software stack used to train and deploy models, training and testing data management systems, container registries, software repositories, and model zoos. This information can be used to identify targets for further collection, exfiltr' },
  { id: 'AML.T0011', name: 'User Execution', tactics: ['AML.TA0005'], description: 'An adversary may rely upon specific actions by a user in order to gain execution. Users may inadvertently execute unsafe code introduced via AI Supply Chain Compromise. Users may be subjected to social engineering to get them to execute malicious code by, for example, opening a malicious document file or link.' },
  { id: 'AML.T0012', name: 'Valid Accounts', tactics: ['AML.TA0004', 'AML.TA0012'], description: 'Adversaries may obtain and abuse credentials of existing accounts as a means of gaining Initial Access. Credentials may take the form of usernames and passwords of individual user accounts or API keys that provide access to various AI resources and services. Compromised credentials may provide access to additional AI artifacts and allow the adversary to perform Discover AI Artifacts. Compromised c' },
  { id: 'AML.T0015', name: 'Evade AI Model', tactics: ['AML.TA0004', 'AML.TA0007', 'AML.TA0011'], description: 'Adversaries can Craft Adversarial Data that prevents an AI model from correctly identifying the contents of the data or Generate Deepfakes that fools an AI model expecting authentic data. This technique can be used to evade a downstream task where AI is utilized. The adversary may evade AI-based virus/malware detection or network scanning towards the goal of a traditional cyber attack. AI model ev' },
  { id: 'AML.T0018', name: 'Manipulate AI Model', tactics: ['AML.TA0006', 'AML.TA0001'], description: 'Adversaries may directly manipulate an AI model to change its behavior or introduce malicious code. Manipulating a model gives the adversary a persistent change in the system. This can include poisoning the model by changing its weights, modifying the model architecture to change its behavior, and embedding malware which may be executed when the model is loaded.' },
  { id: 'AML.T0024', name: 'Exfiltration via AI Inference API', tactics: ['AML.TA0010'], description: 'Adversaries may exfiltrate private information via AI Model Inference API Access. AI Models have been shown leak private information about their training data (e.g. Infer Training Data Membership, Invert AI Model). The model itself may also be extracted (Extract AI Model) for the purposes of AI Intellectual Property Theft. Exfiltration of information relating to private training data raises privac' },
  { id: 'AML.T0025', name: 'Exfiltration via Cyber Means', tactics: ['AML.TA0010'], description: 'Adversaries may exfiltrate AI artifacts or other information relevant to their goals via traditional cyber means. See the ATT&CK Exfiltration tactic for more information.' },
  { id: 'AML.T0029', name: 'Denial of AI Service', tactics: ['AML.TA0011'], description: 'Adversaries may target AI-enabled systems with a flood of requests for the purpose of degrading or shutting down the service. Since many AI systems require significant amounts of specialized compute, they are often expensive bottlenecks that can become overloaded. Adversaries can intentionally craft inputs that require heavy amounts of useless compute from the AI system.' },
  { id: 'AML.T0046', name: 'Spamming AI System with Chaff Data', tactics: ['AML.TA0011'], description: 'Adversaries may spam the AI system with chaff data that causes increase in the number of detections. This can cause analysts at the victim organization to waste time reviewing and correcting incorrect inferences. Adversaries may also spam AI agents with excessive low-severity auditable events or agentic actions that require a human-in-the-loop, wasting time for the victim organization in human rev' },
  { id: 'AML.T0031', name: 'Erode AI Model Integrity', tactics: ['AML.TA0011'], description: 'Adversaries may degrade the target model\'s performance with adversarial data inputs to erode confidence in the system over time. This can lead to the victim organization wasting time and money both attempting to fix the system and performing the tasks it was meant to automate by hand.' },
  { id: 'AML.T0034', name: 'Cost Harvesting', tactics: ['AML.TA0011'], description: 'Adversaries may deliberately drive a victim\'s AI services beyond normal operating capacity with the intent of increasing the cost of services. This may be achieved via high-volume, low-complexity queries (Excessive Queries) or low-volume, high-complexity queries (Resource-Intensive Queries). In Generative AI or Agentic AI systems, adversarial prompts may be introduced into the model\'s context to c' },
  { id: 'AML.T0035', name: 'AI Artifact Collection', tactics: ['AML.TA0009'], description: 'Adversaries may collect AI artifacts for Exfiltration or for use in AI Attack Staging. AI artifacts include models and datasets as well as other telemetry data produced when interacting with a model.' },
  { id: 'AML.T0036', name: 'Data from Information Repositories', tactics: ['AML.TA0009'], description: 'Adversaries may leverage information repositories to mine valuable information. Information repositories are tools that allow for storage of information, typically to facilitate collaboration or information sharing between users, and can store a wide variety of data that may aid adversaries in further objectives, or direct access to the target information. Information stored in a repository may va' },
  { id: 'AML.T0037', name: 'Data from Local System', tactics: ['AML.TA0009'], description: 'Adversaries may search local system sources, such as file systems and configuration files or local databases, to find files of interest and sensitive data prior to Exfiltration. This can include basic fingerprinting information and sensitive data such as ssh keys.' },
  { id: 'AML.T0042', name: 'Verify Attack', tactics: ['AML.TA0001'], description: 'Adversaries can verify the efficacy of their attack via an inference API or access to an offline copy of the target model. This gives the adversary confidence that their approach works and allows them to carry out the attack at a later time of their choosing. The adversary may verify the attack once but use it against many edge devices running copies of the target model. The adversary may verify t' },
  { id: 'AML.T0043', name: 'Craft Adversarial Data', tactics: ['AML.TA0001'], description: 'Adversarial data are inputs to an AI model that have been modified such that they cause the adversary\'s desired effect in the target model. Effects can range from misclassification, to missed detections, to maximizing energy consumption. Typically, the modification is constrained in magnitude or location so that a human still perceives the data as if it were unmodified, but human perceptibility ma' },
  { id: 'AML.T0048', name: 'External Harms', tactics: ['AML.TA0011'], description: 'Adversaries may abuse their access to a victim system and use its resources or capabilities to further their goals by causing harms external to that system. These harms could affect the organization (e.g. Financial Harm, Reputational Harm), its users (e.g. User Harm), or the general public (e.g. Societal Harm).' },
  { id: 'AML.T0049', name: 'Exploit Public-Facing Application', tactics: ['AML.TA0004'], description: 'Adversaries may attempt to take advantage of a weakness in an Internet-facing computer or program using software, data, or commands in order to cause unintended or unanticipated behavior. The weakness in the system can be a bug, a glitch, or a design vulnerability. These applications are often websites, but can include databases (like SQL), standard services (like SMB or SSH), network device admin' },
  { id: 'AML.T0050', name: 'Command and Scripting Interpreter', tactics: ['AML.TA0005'], description: 'Adversaries may abuse command and script interpreters to execute commands, scripts, or binaries. These interfaces and languages provide ways of interacting with computer systems and are a common feature across many different platforms. Most systems come with some built-in command-line interface and scripting capabilities, for example, macOS and Linux distributions include some flavor of Unix Shell' },
  { id: 'AML.T0051', name: 'LLM Prompt Injection', tactics: ['AML.TA0005'], description: 'An adversary may craft malicious prompts as inputs to an LLM that cause the LLM to act in unintended ways. These "prompt injections" are often designed to cause the model to ignore aspects of its original instructions and follow the adversary\'s instructions instead. Prompt Injections can be an initial access vector to the LLM that provides the adversary with a foothold to carry out other steps in ' },
  { id: 'AML.T0052', name: 'Phishing', tactics: ['AML.TA0004', 'AML.TA0015'], description: 'Adversaries may send phishing messages to gain access to victim systems. All forms of phishing are electronically delivered social engineering. Phishing can be targeted, known as spearphishing. In spearphishing, a specific individual, company, or industry will be targeted by the adversary. More generally, adversaries can conduct non-targeted phishing, such as in mass malware spam campaigns. Genera' },
  { id: 'AML.T0053', name: 'AI Agent Tool Invocation', tactics: ['AML.TA0005', 'AML.TA0012'], description: 'Adversaries may use their access to an AI agent to invoke tools the agent has access to. LLMs are often connected to other services or resources via tools to increase their capabilities. Tools may include integrations with other applications, access to public or private data sources, and the ability to execute code. This may allow adversaries to execute API calls to integrated applications or serv' },
  { id: 'AML.T0054', name: 'LLM Jailbreak', tactics: ['AML.TA0012', 'AML.TA0007'], description: 'Adversaries may induce a large language model (LLM) to ignore, circumvent, or override its safety/alignment behaviors and/or guardrails to elicit outputs the model is intended to withhold. Once jailbroken, the LLM may be used in unintended ways by the adversary. Jailbreaks may be achieved via adversarial prompting, or by modifying model weights or safety mechanisms. Adversaries may attempt a jailb' },
  { id: 'AML.T0055', name: 'Unsecured Credentials', tactics: ['AML.TA0013'], description: 'Adversaries may search compromised systems to find and obtain insecurely stored credentials. These credentials can be stored and/or misplaced in many locations on a system, including plaintext files (e.g. bash history), environment variables, operating system, or application-specific repositories (e.g. Credentials in Registry), or other specialized files/artifacts (e.g. private keys).' },
  { id: 'AML.T0056', name: 'Extract LLM System Prompt', tactics: ['AML.TA0010'], description: 'Adversaries may attempt to extract a large language model\'s (LLM) system prompt. This can be done via prompt injection to induce the model to reveal its own system prompt or may be extracted from a configuration file. System prompts can be a portion of an AI provider\'s competitive advantage and are thus valuable intellectual property that may be targeted by adversaries.' },
  { id: 'AML.T0057', name: 'LLM Data Leakage', tactics: ['AML.TA0010'], description: 'Adversaries may craft prompts that induce the LLM to leak sensitive information. This can include private user data or proprietary information. The leaked information may come from proprietary training data, data sources the LLM is connected to, or information from other users of the LLM.' },
  { id: 'AML.T0058', name: 'Publish Poisoned Models', tactics: ['AML.TA0003'], description: 'Adversaries may publish a poisoned model to a public location such as a model registry or code repository. The poisoned model may be a novel model or a poisoned variant of an existing open-source model. This model may be introduced to a victim system via AI Supply Chain Compromise.' },
  { id: 'AML.T0059', name: 'Erode Dataset Integrity', tactics: ['AML.TA0011'], description: 'Adversaries may poison or manipulate portions of a dataset to reduce its usefulness, reduce trust, and cause users to waste resources correcting errors.' },
  { id: 'AML.T0060', name: 'Publish Hallucinated Entities', tactics: ['AML.TA0003'], description: 'Adversaries may create an entity they control, such as a software package, website, or email address to a source hallucinated by an LLM. The hallucinations may take the form of package names commands, URLs, company names, or email addresses that point the victim to the entity controlled by the adversary. When the victim interacts with the adversary-controlled entity, the attack can proceed.' },
  { id: 'AML.T0061', name: 'LLM Prompt Self-Replication', tactics: ['AML.TA0006'], description: 'An adversary may use a carefully crafted LLM Prompt Injection designed to cause the LLM to replicate the prompt as part of its output. This allows the prompt to propagate to other LLMs and persist on the system. The self-replicating prompt is typically paired with other malicious instructions (ex: LLM Jailbreak, LLM Data Leakage).' },
  { id: 'AML.T0062', name: 'Discover LLM Hallucinations', tactics: ['AML.TA0008'], description: 'Adversaries may prompt large language models and identify hallucinated entities. They may request software packages, commands, URLs, organization names, or e-mail addresses, and identify hallucinations with no connected real-world source. Discovered hallucinations provide the adversary with potential targets to Publish Hallucinated Entities. Different LLMs have been shown to produce the same hallu' },
  { id: 'AML.T0063', name: 'Discover AI Model Outputs', tactics: ['AML.TA0008'], description: 'Adversaries may discover model outputs, such as class scores, whose presence is not required for the system to function and are not intended for use by the end user. Model outputs may be found in logs or may be included in API responses. Model outputs may enable the adversary to identify weaknesses in the model and develop attacks.' },
  { id: 'AML.T0064', name: 'Gather RAG-Indexed Targets', tactics: ['AML.TA0002'], description: 'Adversaries may identify data sources used in retrieval augmented generation (RAG) systems for targeting purposes. By pinpointing these sources, attackers can focus on poisoning or otherwise manipulating the external data repositories the AI relies on. RAG-indexed data may be identified in public documentation about the system, or by interacting with the system directly and observing any indicatio' },
  { id: 'AML.T0065', name: 'LLM Prompt Crafting', tactics: ['AML.TA0003'], description: 'Adversaries may use their acquired knowledge of the target generative AI system to craft prompts that bypass its defenses and allow malicious instructions to be executed. The adversary may iterate on the prompt to ensure that it works as-intended consistently.' },
  { id: 'AML.T0066', name: 'Retrieval Content Crafting', tactics: ['AML.TA0003'], description: 'Adversaries may write content designed to be retrieved by user queries and influence a user of the system in some way. This abuses the trust the user has in the system. The crafted content can be combined with a prompt injection. It can also stand alone in a separate document or email. The adversary must get the crafted content into the victim\'s database, such as a vector database used in a r' },
  { id: 'AML.T0067', name: 'LLM Trusted Output Components Manipulation', tactics: ['AML.TA0007'], description: 'Adversaries may utilize prompts to a large language model (LLM) which manipulate various components of its response in order to make it appear trustworthy to the user. This helps the adversary continue to operate in the victim\'s environment and evade detection by the users it interacts with. The LLM may be instructed to tailor its language to appear more trustworthy to the user or attempt to manip' },
  { id: 'AML.T0068', name: 'LLM Prompt Obfuscation', tactics: ['AML.TA0007'], description: 'Adversaries may hide or otherwise obfuscate prompt injections or retrieval content to avoid detection from humans, large language model (LLM) guardrails, or other detection mechanisms. For text inputs, this may include modifying how the instructions are rendered such as small text, text colored the same as the background, or hidden HTML elements. For multi-modal inputs, malicious instructions coul' },
  { id: 'AML.T0069', name: 'Discover LLM System Information', tactics: ['AML.TA0008'], description: 'The adversary is trying to discover something about the large language model\'s (LLM) system information. This may be found in a configuration file containing the system instructions or extracted via interactions with the LLM. The desired information may include the full system prompt, special characters that have significance to the LLM or keywords indicating functionality available to the LLM. In' },
  { id: 'AML.T0070', name: 'RAG Poisoning', tactics: ['AML.TA0006'], description: 'Adversaries may inject malicious content into data indexed by a retrieval augmented generation (RAG) system to contaminate a future thread through RAG-based search results. This may be accomplished by placing manipulated documents in a location the RAG indexes (see Gather RAG-Indexed Targets). The content may be targeted such that it would always surface as a search result for a specific user quer' },
  { id: 'AML.T0071', name: 'False RAG Entry Injection', tactics: ['AML.TA0007'], description: 'Adversaries may introduce false entries into a victim\'s retrieval augmented generation (RAG) database. Content designed to be interpreted as a document by the large language model (LLM) used in the RAG system is included in a data source being ingested into the RAG database. When RAG entry including the false document is retrieved, the LLM is tricked into treating part of the retrieved content as ' },
  { id: 'AML.T0072', name: 'Reverse Shell', tactics: ['AML.TA0014'], description: 'Adversaries may utilize a reverse shell to communicate and control the victim system. Typically, a user uses a client to connect to a remote machine which is listening for connections. With a reverse shell, the adversary is listening for incoming connections initiated from the victim system.' },
  { id: 'AML.T0073', name: 'Impersonation', tactics: ['AML.TA0007'], description: 'Adversaries may impersonate a trusted person or organization in order to persuade and trick a target into performing some action on their behalf. For example, adversaries may communicate with victims (via Phishing, or Spearphishing via Social Engineering LLM) while impersonating a known sender such as an executive, colleague, or third-party vendor. Established trust can then be leveraged to accomp' },
  { id: 'AML.T0074', name: 'Masquerading', tactics: ['AML.TA0007'], description: 'Adversaries may attempt to manipulate features of their artifacts to make them appear legitimate or benign to users and/or security tools. Masquerading occurs when the name or location of an object, legitimate or malicious, is manipulated or abused for the sake of evading defenses and observation. This may include manipulating file metadata, tricking users into misidentifying the file type, and gi' },
  { id: 'AML.T0075', name: 'Cloud Service Discovery', tactics: ['AML.TA0008'], description: 'Adversaries may attempt to enumerate the cloud services running on a system after gaining access. These methods can differ from platform-as-a-service (PaaS), to infrastructure-as-a-service (IaaS), software-as-a-service (SaaS), or AI-as-a-service (AIaaS). Many services exist throughout the various cloud providers and can include Continuous Integration and Continuous Delivery (CI/CD), Lambda Functio' },
  { id: 'AML.T0076', name: 'Corrupt AI Model', tactics: ['AML.TA0007'], description: 'An adversary may purposefully corrupt a malicious AI model file so that it cannot be successfully deserialized in order to evade detection by a model scanner. The corrupt model may still successfully execute malicious code before deserialization fails.' },
  { id: 'AML.T0077', name: 'LLM Response Rendering', tactics: ['AML.TA0010'], description: 'An adversary may get a large language model (LLM) to respond with private information that is hidden from the user when the response is rendered by the user\'s client. The private information is then exfiltrated. This can take the form of rendered images, which automatically make a request to an adversary controlled server. The adversary gets AI to present an image to the user, which is rendered by' },
  { id: 'AML.T0078', name: 'Drive-by Compromise', tactics: ['AML.TA0004'], description: 'Adversaries may gain access to an AI system through a user visiting a website over the normal course of browsing, or an AI agent retrieving information from the web on behalf of a user. Websites can contain an LLM Prompt Injection which, when executed, can change the behavior of the AI model. The same approach may be used to deliver other types of malicious code that don\'t target AI directly (See ' },
  { id: 'AML.T0079', name: 'Stage Capabilities', tactics: ['AML.TA0003'], description: 'Adversaries may upload, install, or otherwise set up capabilities that can be used during targeting. To support their operations, an adversary may need to take capabilities they developed (Develop Capabilities) or obtained (Obtain Capabilities) and stage them on infrastructure under their control. These capabilities may be staged on infrastructure that was previously purchased/rented by the advers' },
  { id: 'AML.T0080', name: 'AI Agent Context Poisoning', tactics: ['AML.TA0006'], description: 'Adversaries may attempt to manipulate the context used by an AI agent\'s large language model (LLM) to influence the responses it generates or actions it takes. This allows an adversary to persistently change the behavior of the target agent and further their goals. Context poisoning can be accomplished by prompting the an LLM to add instructions or preferences to memory (See Memory) or by simply p' },
  { id: 'AML.T0081', name: 'Modify AI Agent Configuration', tactics: ['AML.TA0006', 'AML.TA0007'], description: 'Adversaries may modify the configuration files for AI agents on a system. This allows malicious changes to persist beyond the life of a single agent and affects any agents that share the configuration. Configuration changes may include modifications to the system prompt, tampering with or replacing knowledge sources, modification to settings of connected tools, and more. Through those changes, an ' },
  { id: 'AML.T0082', name: 'RAG Credential Harvesting', tactics: ['AML.TA0013'], description: 'Adversaries may attempt to use their access to a large language model (LLM) on the victim\'s system to collect credentials. Credentials may be stored in internal documents which can inadvertently be ingested into a RAG database, where they can ultimately be retrieved by an AI agent.' },
  { id: 'AML.T0083', name: 'Credentials from AI Agent Configuration', tactics: ['AML.TA0013'], description: 'Adversaries may access the credentials of other tools or services on a system from the configuration of an AI agent. AI Agents often utilize external tools or services to take actions, such as querying databases, invoking APIs, or interacting with cloud resources. To enable these functions, credentials like API keys, tokens, and connection strings are frequently stored in configuration files. Whil' },
  { id: 'AML.T0084', name: 'Discover AI Agent Configuration', tactics: ['AML.TA0008'], description: 'Adversaries may attempt to discover configuration information for AI agents present on the victim\'s system. Agent configurations can include tools or services they have access to. Adversaries may directly access agent configuring dashboards or configuration files. They may also obtain configuration details by prompting the agent with questions such as "What tools do you have access to?" Adversarie' },
  { id: 'AML.T0085', name: 'Data from AI Services', tactics: ['AML.TA0009'], description: 'Adversaries may use their access to a victim organization\'s AI-enabled services to collect proprietary or otherwise sensitive information. As organizations adopt generative AI in centralized services for accessing an organization\'s data, such as with chat agents which can access retrieval augmented generation (RAG) databases and other data sources via tools, they become increasingly valuable targe' },
  { id: 'AML.T0086', name: 'Exfiltration via AI Agent Tool Invocation', tactics: ['AML.TA0010'], description: 'AI agent tools capable of performing write operations may be invoked to exfiltrate data to an adversary. Sensitive information can be encoded into the tool\'s input parameters and transmitted to an adversary-controlled location (such as an inbox, document, or server) as part of a seemingly legitimate action. Variants include sending emails, creating or modifying documents, updating CRM records, or ' },
  { id: 'AML.T0087', name: 'Gather Victim Identity Information', tactics: ['AML.TA0002'], description: 'Adversaries may gather information about the victim\'s identity that can be used during targeting. Information about identities may include a variety of details, including personal data (ex: employee names, email addresses, photos, etc.) as well as sensitive details such as credentials or multi-factor authentication (MFA) configurations. Adversaries may gather this information in various ways, such' },
  { id: 'AML.T0088', name: 'Generate Deepfakes', tactics: ['AML.TA0001'], description: 'Adversaries may use generative artificial intelligence (GenAI) to create synthetic media (i.e. imagery, video, audio, and text) that appear authentic. These "deepfakes" may mimic a real person or depict fictional personas. Adversaries may use deepfakes for impersonation to conduct Phishing or to evade AI applications such as biometric identity verification systems (see Evade AI Model). Manipulatio' },
  { id: 'AML.T0089', name: 'Process Discovery', tactics: ['AML.TA0008'], description: 'Adversaries may attempt to get information about processes running on a system. Once obtained, this information could be used to gain an understanding of common AI-related software/applications running on systems within the network. Administrator or otherwise elevated access may provide better process details. Identifying the AI software stack can then lead an adversary to new targets and attack p' },
  { id: 'AML.T0090', name: 'OS Credential Dumping', tactics: ['AML.TA0013'], description: 'Adversaries may extract credentials from OS caches, application memory, or other sources on a compromised system. Credentials are often in the form of a hash or clear text, and can include usernames and passwords, application tokens, or other authentication keys. Credentials can be used to perform Lateral Movement to access other AI services such as AI agents, LLMs, or AI inference APIs. Credentia' },
  { id: 'AML.T0091', name: 'Use Alternate Authentication Material', tactics: ['AML.TA0015'], description: 'Adversaries may use alternate authentication material, such as password hashes, Kerberos tickets, and application access tokens, in order to move laterally within an environment and bypass normal system access controls. AI services commonly use alternate authentication material as a primary means for users to make queries, making them vulnerable to this technique.' },
  { id: 'AML.T0092', name: 'Manipulate User LLM Chat History', tactics: ['AML.TA0007'], description: 'Adversaries may manipulate a user\'s large language model (LLM) chat history to cover the tracks of their malicious behavior. They may hide persistent changes they have made to the LLM\'s behavior, or obscure their attempts at discovering private information about the user. To do so, adversaries may delete or edit existing messages or create new threads as part of their coverup. This is feasible if ' },
  { id: 'AML.T0093', name: 'Prompt Infiltration via Public-Facing Application', tactics: ['AML.TA0004', 'AML.TA0006'], description: 'An adversary may introduce malicious prompts into the victim\'s system via a public-facing application with the intention of it being ingested by an AI at some point in the future and ultimately having a downstream effect. This may occur when a data source is indexed by a retrieval augmented generation (RAG) system, when a rule triggers an action by an AI agent, or when a user utilizes a large lang' },
  { id: 'AML.T0094', name: 'Delay Execution of LLM Instructions', tactics: ['AML.TA0007'], description: 'Adversaries may include instructions to be followed by the AI system in response to a future event, such as a specific keyword or the next interaction, in order to evade detection or bypass controls placed on the AI system. For example, an adversary may include "If the user submits a new request..." followed by the malicious instructions as part of their prompt. AI agents can include security meas' },
  { id: 'AML.T0095', name: 'Search Open Websites/Domains', tactics: ['AML.TA0002'], description: 'Adversaries may search public websites and/or domains for information about victims that can be used during targeting. Information about victims may be available in various online sites, such as social media, new sites, or domains owned by the victim. Adversaries may find the information they seek to gather via search engines. They can use precise search queries to identify software platforms or s' },
  { id: 'AML.T0096', name: 'AI Service API', tactics: ['AML.TA0014'], description: 'Adversaries may communicate using the API of an AI service on the victim\'s system. The adversary\'s commands to the victim system, and often the results, are embedded in the normal traffic of the AI service. An AI service API command and control channel is covert because the adversary\'s commands blend in with normal communications, so an adversary may use this technique to avoid detection. Using ex' },
  { id: 'AML.T0097', name: 'Virtualization/Sandbox Evasion', tactics: ['AML.TA0007'], description: 'Adversaries may employ various means to detect and avoid virtualization and analysis environments. This may include changing behaviors based on the results of checks for the presence of artifacts indicative of a virtual machine environment (VME) or sandbox. If the adversary detects a VME, they may alter their malware to disengage from the victim or conceal the core functions of the implant. They m' },
  { id: 'AML.T0098', name: 'AI Agent Tool Credential Harvesting', tactics: ['AML.TA0013'], description: 'Adversaries may attempt to use their access to an AI agent on the victim\'s system to retrieve data from available agent tools to collect credentials. Agent tools may connect to a wide range of sources that may contain credentials including document stores (e.g. SharePoint, OneDrive or Google Drive), code repositories (e.g. GitHub or GitLab), or enterprise productivity tools (e.g. as email provider' },
  { id: 'AML.T0099', name: 'AI Agent Tool Data Poisoning', tactics: ['AML.TA0006'], description: 'Adversaries may place malicious content on a victim\'s system where it can be retrieved by an AI Agent Tool. This may be accomplished by placing documents in a location that will be ingested by a service the AI agent has associated tools for. The content may be targeted such that it would often be retrieved by common queries. The adversary\'s content may include false or misleading information. It m' },
  { id: 'AML.T0100', name: 'AI Agent Clickbait', tactics: ['AML.TA0005'], description: 'Adversaries may craft deceptive web content designed to bait Computer-Using AI agents or AI web browsers into taking unintended actions, such as clicking buttons, copying code, or navigating to specific web pages. These attacks exploit the agent\'s interpretation of UI content, visual cues, or prompt-like language embedded in the site. When successful, they can lead the agent to inadvertently copy ' },
  { id: 'AML.T0101', name: 'Data Destruction via AI Agent Tool Invocation', tactics: ['AML.TA0011'], description: 'Adversaries may invoke an AI agent\'s tool capable of performing mutative operations to perform Data Destruction. Adversaries may destroy data and files on specific systems or in large numbers on a network to interrupt availability to systems, services, and network resources.' },
  { id: 'AML.T0102', name: 'Generate Malicious Commands', tactics: ['AML.TA0001'], description: 'Adversaries may use large language models (LLMs) to dynamically generate malicious commands from natural language. Dynamically generated commands may be harder detect as the attack signature is constantly changing. AI-generated commands may also allow adversaries to more rapidly adapt to different environments and adjust their tactics. Adversaries may utilize LLMs present in the victim\'s environme' },
  { id: 'AML.T0103', name: 'Deploy AI Agent', tactics: ['AML.TA0005'], description: 'Adversaries may launch AI agents in the victim\'s environment to execute actions on their behalf. AI agents may have access to a wide range of tools and data sources, as well as permissions to access and interact with other services and systems in the victim\'s environment. The adversary may leverage these capabilities to carry out their operations. Adversaries may configure the AI agent by providin' },
  { id: 'AML.T0104', name: 'Publish Poisoned AI Agent Tool', tactics: ['AML.TA0003'], description: 'Adversaries may create and publish poisoned AI agent tools. Poisoned tools may contain an LLM Prompt Injection, which can lead to a variety of impacts. Tools may be published to open source version control repositories (e.g. GitHub, GitLab), to package registries (e.g. npm), or to repositories specifically designed for sharing tools (e.g. OpenClaw Hub). These registries may be largely unregulated ' },
  { id: 'AML.T0105', name: 'Escape to Host', tactics: ['AML.TA0012'], description: 'Adversaries may break out of a container or virtualized environment to gain access to the underlying host. This can allow an adversary access to other containerized or virtualized resources from the host level or to the host itself. In principle, containerized / virtualized resources should provide a clear separation of application functionality and be isolated from the host environment. There are' },
  { id: 'AML.T0106', name: 'Exploitation for Credential Access', tactics: ['AML.TA0013'], description: 'Adversaries may exploit software vulnerabilities in an attempt to collect credentials. Exploitation of a software vulnerability occurs when an adversary takes advantage of a programming error in a program, service, or within the operating system software or kernel itself to execute adversary-controlled code.' },
  { id: 'AML.T0107', name: 'Exploitation for Defense Evasion', tactics: ['AML.TA0007'], description: 'Adversaries may exploit a system or application vulnerability to bypass security features. Exploitation of a vulnerability occurs when an adversary takes advantage of a programming error in a program, service, or within the operating system software or kernel itself to execute adversary-controlled code. Vulnerabilities may exist in defensive security software that can be used to disable or circumv' },
  { id: 'AML.T0108', name: 'AI Agent', tactics: ['AML.TA0014'], description: 'Adversaries may abuse AI agents present on the victim\'s system for command and control. AI agents are often granted access to tools that can execute shell commands, reach out to the internet, and interact with other services in the victim\'s environment, making them capable C2 agents. The adversary may modify the behavior of an AI agent for C2 via LLM Prompt Injection and rely on the agent\'s abilit' },
  { id: 'AML.T0109', name: 'AI Supply Chain Rug Pull', tactics: ['AML.TA0007'], description: 'Adversaries may publish legitimate AI components or software, gain user adoption, then push an update with a malicious variant, leading to AI Supply Chain Compromise. More scrutiny is often placed on a supply chain dependency when it is first being considered for inclusion in an AI system. Performing a rug pull may allow adversaries to bypass these defenses and be more likely to achieve Initial Ac' },
  { id: 'AML.T0110', name: 'AI Agent Tool Poisoning', tactics: ['AML.TA0006'], description: 'Adversaries may achieve persistence by poisoning tools used by AI agents including built-in tools or tools available to the agent via Model Context Protocol (MCP) connections. This involves compromising benign tools already integrated into the agent\'s environment. By altering tool behavior such as modifying parameters or descriptions, injecting hidden logic, or redirecting outputs, attackers can m' },
  { id: 'AML.T0111', name: 'AI Supply Chain Reputation Inflation', tactics: ['AML.TA0007'], description: 'AI Supply Chain Reputation Inflation is the process of building or leveraging genuinely credible-looking trust signals to increase the perceived legitimacy of AI supply chain components, with the goal of driving adoption of malicious or compromised assets. Adversaries use established developer accounts with a history of legitimate projects and contributions to publish AI models, datasets, packages' },
  { id: 'AML.T0112', name: 'Machine Compromise', tactics: ['AML.TA0011'], description: 'Adversaries may compromise a machine by exploiting or manipulating AI-enabled components on the system. Compromising a victim system allows the adversary to execute arbitrary code, steal credentials, exfiltrate data, and continue to persist on the system. Adversaries may target a Local AI Agent which if compromised grants them the capabilities and permissions of the agent, or AI Artifacts which ca' },
];

// Convenience: controls-style flat list matching the shape of other framework files
// (id, name, category, priority) so it plugs into existing control-mapping UI/logic.
export const MITRE_ATLAS_CONTROLS = ATLAS_TACTICS.map(t => ({
  id: t.id,
  name: t.name,
  category: 'Tactic',
  priority: 'High',
  description: t.description,
}));
